import request from '@/utils/request'

// 档案数据管理
const profile = {
  // 获取完整档案数据
  getData() {
    console.log('获取完整档案数据')
    return request.get('/api/v1/users/profile/data/')
  },

  // 获取简历完整度
  getCompleteness() {
    console.log('获取简历完整度')
    return request.get('/api/v1/users/profile/completeness/')
  },

  // 更新完整档案数据
  updateData(data) {
    console.log('更新完整档案数据:', data)
    return request({
      url: '/api/v1/users/profile/data/',
      method: 'put',
      data
    })
  },

  // 更新单个模块数据
  updateModule(type, data) {
    console.log('更新模块数据:', { type, data })
    // 如果是基本信息，使用完整档案接口
    if (type === 'basic_info') {
      return request({
        url: '/api/v1/users/profile/basic/',
        method: 'post',
        data: {
          ...data,
          id: data.id
        }
      })
    }

    // 其他模块使用独立接口
    const urlMap = {
      work_experience: 'work-experiences',
      education: 'educations',
      project: 'projects',
      skill: 'skills',
      certificate: 'certificates',
      language: 'languages',
      portfolio: 'portfolios',
      social_link: 'social-links',
      job_intention: 'job-intention'
    }

    return request({
      url: `/api/v1/users/profile/${urlMap[type] || type}/`,
      method: 'put',
      data
    })
  },

  // 添加模块项目
  addModuleItem(type, data) {
    console.log('添加模块项目:', { type, data })
    const urlMap = {
      work_experience: 'work-experiences',
      education: 'educations',
      project: 'projects',
      skill: 'skills',
      certificate: 'certificates',
      language: 'languages',
      portfolio: 'portfolios',
      social_link: 'social-links'
    }

    return request({
      url: `/api/v1/users/profile/${urlMap[type] || type}/`,
      method: 'post',
      data
    })
  },

  // 删除模块项目
  deleteModuleItem(type, id) {
    console.log('删除模块项目:', { type, id })
    const urlMap = {
      work_experience: 'work-experiences',
      education: 'educations',
      project: 'projects',
      skill: 'skills',
      certificate: 'certificates',
      language: 'languages',
      portfolio: 'portfolios',
      social_link: 'social-links'
    }

    return request({
      url: `/api/v1/users/profile/${urlMap[type] || type}/${id}/`,
      method: 'delete'
    })
  },

  // 上传头像
  uploadAvatar(formData) {
    console.log('上传头像')
    return request({
      url: '/api/v1/users/profile/avatar/upload/',
      method: 'post',
      headers: {
        'Content-Type': 'multipart/form-data'
      },
      data: formData
    })
  },

  // 获取布局配置
  getLayout() {
    console.log('获取布局配置')
    return request.get('/api/v1/users/profile/layout/')
  },

  // 更新布局配置
  updateLayout(type, layout) {
    console.log('更新布局配置:', { type, layout })
    return request({
      url: `/api/v1/users/profile/layout/${type}/`,
      method: 'put',
      data: layout
    })
  },

  // 获取所有模块数据
  getModules() {
    return request({
      url: '/api/v1/users/profile/modules/',
      method: 'get'
    })
  }
}

export default profile
